#define CRIMSON_RX_CHANNELS 4
#define CRIMSON_TX_CHANNELS 4

using namespace uhd;
using namespace uhd::usrp;

static const double TX_SIGN = -1;
static const double RX_SIGN = 1;

static const double DSP_NCO_SHIFT_HZ = 25e6;

/***********************************************************************
 * Helper Functions
 **********************************************************************/
